In the Objects version, you keep delegation, but replace the long switch statement with an object lookup table that maps an input’s type (like "email" or "date") to the appropriate handler function. This is the cleanest scaling strategy: adding a new input often becomes “add one row to the handler table.”

Best use cases: scalable systems, maintainable demos, codebases where you want to add new behavior without editing a monster conditional. This is also a stepping stone toward more advanced patterns (config-driven forms, reusable components, validation maps).
Worst use cases: when the type alone isn’t enough to determine behavior. If two text inputs need different logic, mapping only by type can be too blunt—then you’ll want to dispatch by id, name, or data-* attributes instead.<!DOCTYPE html>
<!--
  HTML input demo using:
    - Event delegation (one listener for many inputs)
    - Data-driven handlers (mapping inputs to functions)

  same interface, same behavior, 
  but now the JavaScript is data-driven. 
  Instead of a long switch, we have a lookup table (an object) 
  that maps inputs to handler functions.
-->

<head>
  <title>Input types</title>

  <style>
    .div1 {
      width: 75%;
      background-color: cornsilk;
      padding: 25px;
      margin: 50px auto;
    }
  </style>
</head>

<body>

  <div class="div1">
    <h1>HTML Input Types – Data-Driven Event Handling</h1>
    <p>Input types are mapped to handler functions through a lookup table.</p>

    <!-- Log output -->
    <div id="log" style="border:1px solid #444;
      padding:10px;
      height:200px;
      overflow-y:auto;
      margin-bottom:20px;
      background:#f9f9f9;">
    </div>

    <!-- Form with input fields -->
    <form id="demoForm">
      <table>
        <tr>
          <td><label for="firstName">First Name:</label></td>
          <td><input type="text" id="firstName"></td>
        </tr>
        <tr>
          <td><label for="lastName">Last Name:</label></td>
          <td><input type="text" id="lastName"></td>
        </tr>

        <tr>
          <td colspan="2" style="text-align:center;">
            <button type="button" id="buttonInput">Button</button>
            <button type="reset">Reset</button>
            <button type="submit">Submit</button>
          </td>
        </tr>
      </table>
    </form>
  </div>

  <script>
    /*
      Writes a message to the log div and auto-scrolls.
    */
    function log(message) {
      if (message === "Form reset") {
        document.getElementById("log").innerHTML = "";
      }

      const logDiv = document.getElementById("log");
      const entry = document.createElement("div");
      entry.textContent = message;
      logDiv.appendChild(entry);
      logDiv.scrollTop = logDiv.scrollHeight;
    }

    /*
      Handler table:
      Keys are input identifiers.
      Values are functions that know how to log that input.
      This replaces a long conditional.
    */
    const inputHandlers = {
      firstName: el => log("First Name: " + el.value),
      lastName: el => log("Last Name: " + el.value)
    };

    /*
      Attach a few top-level listeners when the DOM is ready:
        - Delegated 'input' on the form
        - 'reset' and 'submit' on the form
        - Separate click handler for the plain button
    */
    document.addEventListener("DOMContentLoaded", () => {

      const form = document.getElementById("demoForm");

      // Delegated listener: any input inside the form bubbles up here
      form.addEventListener("input", handleDelegatedEvent);

      form.addEventListener("reset", () => log("Form reset"));

      form.addEventListener("submit", e => {
        e.preventDefault();
        log("Form submitted");
      });

      document.getElementById("buttonInput")
        .addEventListener("click", () => log("Button clicked"));
    });

    /*
      Central delegated handler:
      - Makes sure the event came from an <input>
      - Looks up a handler by input id
      - Calls that handler if it exists
    */
    function handleDelegatedEvent(e) {
      const el = e.target;

      if (el.tagName !== "INPUT") return;

      const handler = inputHandlers[el.id];

      if (handler) {
        handler(el, e); // pass element (and event if needed later)
      }
    }
  </script>
</body>

You usually start with:const request = indexedDB.open("PetsDB", 1);

That open() call can trigger three major events: success, error, and upgrade. The upgrade path is where you create or modify object stores and indexes. That schema work happens during version changes, not casually in the middle of normal reads and writes. (

MDN Web Docs)

A typical setup looks like this:const request = indexedDB.open("PetsDB", 1);

request.onupgradeneeded = (event) => {
  const db = event.target.result;

  const store = db.createObjectStore("pets", {
    keyPath: "id",
    autoIncrement: true
  });

  store.createIndex("name", "name", { unique: false });
  store.createIndex("type", "type", { unique: false });
};

request.onsuccess = (event) => {
  const db = event.target.result;
  console.log("Database opened");
};

request.onerror = (event) => {
  console.error("Database error:", event.target.error);
};

Here, pets is the object store, id is the primary key, and name and type are indexed fields. Object stores and indexes are official IndexedDB concepts, and createIndex() is the standard way to define searchable fields. (

MDN Web Docs)

Use add() when you want to insert a new record and fail if the key already exists.function addPet(db, pet) {
  const tx = db.transaction("pets", "readwrite");
  const store = tx.objectStore("pets");
  const request = store.add(pet);

  request.onsuccess = () => {
    console.log("Pet added");
  };

  request.onerror = (event) => {
    console.error("Add failed:", event.target.error);
  };
}

Example call:addPet(db, {
  name: "Luna",
  type: "Cat",
  age: 3
});

MDN distinguishes add() from put(): add() creates a new record and errors on duplicate keys. (

MDN Web Docs)

Use get().function getPet(db, id) {
  const tx = db.transaction("pets", "readonly");
  const store = tx.objectStore("pets");
  const request = store.get(id);

  request.onsuccess = () => {
    console.log("Found:", request.result);
  };

  request.onerror = (event) => {
    console.error("Read failed:", event.target.error);
  };
}

get() retrieves the object for a specific key and returns a structured clone of the stored value. (

MDN Web Docs)

Use getAll() for convenience.function getAllPets(db) {
  const tx = db.transaction("pets", "readonly");
  const store = tx.objectStore("pets");
  const request = store.getAll();

  request.onsuccess = () => {
    console.log("All pets:", request.result);
  };

  request.onerror = (event) => {
    console.error("Read all failed:", event.target.error);
  };
}

getAll() returns all matching objects, or all objects in the store if you provide no filter. (

MDN Web Docs)

Use a cursor when you want custom filtering, ordered traversal, or streaming through records one at a time.function listPetsWithCursor(db) {
  const tx = db.transaction("pets", "readonly");
  const store = tx.objectStore("pets");
  const request = store.openCursor();

  request.onsuccess = (event) => {
    const cursor = event.target.result;
    if (cursor) {
      console.log(cursor.key, cursor.value);
      cursor.continue();
    } else {
      console.log("No more records");
    }
  };

  request.onerror = (event) => {
    console.error("Cursor failed:", event.target.error);
  };
}

openCursor() is the standard iterator for walking an object store record by record. (

MDN Web Docs)

Use put() when you want an upsert: update if the key exists, insert if it does not.function updatePet(db, pet) {
  const tx = db.transaction("pets", "readwrite");
  const store = tx.objectStore("pets");
  const request = store.put(pet);

  request.onsuccess = () => {
    console.log("Pet saved");
  };

  request.onerror = (event) => {
    console.error("Update failed:", event.target.error);
  };
}

Example:updatePet(db, {
  id: 1,
  name: "Luna",
  type: "Cat",
  age: 4
});

This is where students often get tripped up: put() is not strictly “update only.” It can also insert. If you need “insert only,” use add(). (

MDN Web Docs)

Use delete().function deletePet(db, id) {
  const tx = db.transaction("pets", "readwrite");
  const store = tx.objectStore("pets");
  const request = store.delete(id);

  request.onsuccess = () => {
    console.log("Pet deleted");
  };

  request.onerror = (event) => {
    console.error("Delete failed:", event.target.error);
  };
}

delete() removes a record by key, and it can also take an IDBKeyRange for multiple records. (

MDN Web Docs)

Use clear().function clearPets(db) {
  const tx = db.transaction("pets", "readwrite");
  const store = tx.objectStore("pets");
  const request = store.clear();

  request.onsuccess = () => {
    console.log("All pets removed");
  };

  request.onerror = (event) => {
    console.error("Clear failed:", event.target.error);
  };
}

clear() wipes the entire object store, including index references to those records. It is a chainsaw, not a scalpel. (

MDN Web Docs)

Suppose you created this index:store.createIndex("type", "type", { unique: false });

You can later retrieve pets by type:function getPetsByType(db, type) {
  const tx = db.transaction("pets", "readonly");
  const store = tx.objectStore("pets");
  const index = store.index("type");
  const request = index.getAll(type);

  request.onsuccess = () => {
    console.log(`Pets of type ${type}:`, request.result);
  };

  request.onerror = (event) => {
    console.error("Index query failed:", event.target.error);
  };
}

This is one of the biggest reasons IndexedDB exists at all. Without indexes, you are just shoveling JSON into a browser cave. With indexes, you have searchable local data. (

MDN Web Docs)

Here is a minimal working pattern:const request = indexedDB.open("PetsDB", 1);

request.onupgradeneeded = (event) => {
  const db = event.target.result;
  const store = db.createObjectStore("pets", {
    keyPath: "id",
    autoIncrement: true
  });
  store.createIndex("name", "name", { unique: false });
  store.createIndex("type", "type", { unique: false });
};

request.onsuccess = (event) => {
  const db = event.target.result;

  // CREATE
  let tx = db.transaction("pets", "readwrite");
  let store = tx.objectStore("pets");
  store.add({ name: "Luna", type: "Cat", age: 3 });

  tx.oncomplete = () => {
    // READ ALL
    const readTx = db.transaction("pets", "readonly");
    const readStore = readTx.objectStore("pets");
    const getAllRequest = readStore.getAll();

    getAllRequest.onsuccess = () => {
      console.log("All pets:", getAllRequest.result);

      // UPDATE first record if present
      const pets = getAllRequest.result;
      if (pets.length > 0) {
        const firstPet = pets[0];
        firstPet.age = 4;

        const updateTx = db.transaction("pets", "readwrite");
        updateTx.objectStore("pets").put(firstPet);

        updateTx.oncomplete = () => {
          console.log("Updated pet");

          // DELETE by key
          const deleteTx = db.transaction("pets", "readwrite");
          deleteTx.objectStore("pets").delete(firstPet.id);

          deleteTx.oncomplete = () => {
            console.log("Deleted pet");
          };
        };
      }
    };
  };
};

request.onerror = (event) => {
  console.error("DB open failed:", event.target.error);
};

For primary references, use MDN’s IndexedDB guide and API reference, plus the W3C spec. (

MDN Web Docs)

A while loop repeats as long as its condition is true.let count = 1;

while (count <= 3) {
    console.log("Count is", count);
    count++;
}

Forgetting to update the loop variable is the classic way to create an infinite loop.let n = 1;

while (n <= 5) {
    console.log(n);
    // missing n++
}

This loop never stops. It is the programming equivalent of stepping onto a treadmill and then bolting your shoes to it.

A do...while loop executes the body first and checks the condition afterward.let number = 1;

do {
    console.log("Number:", number);
    number++;
} while (number <= 3);

The for loop is JavaScript’s most compact counting loop.for (let i = 0; i < 5; i++) {
    console.log("i =", i);
}

The general structure is:for (initialization; condition; update) {
    // loop body
}

For this loop:for (let i = 0; i < 3; i++) {
    console.log(i);
}

The engine behaves roughly like this:let i = 0;
while (i < 3) {
    console.log(i);
    i++;
}

That is not literally how the source code is rewritten internally, but it is a useful conceptual model.

Arrays are one of the most common reasons to use iteration.const colors = ["red", "green", "blue"];

for (let i = 0; i < colors.length; i++) {
    console.log("Color at index", i, "is", colors[i]);
}

const colors = ["red", "green", "blue"];

for (let i = 0; i <= colors.length; i++) {
    console.log(colors[i]);
}

This loop uses <= instead of <. When i becomes 3, colors[3] is undefined because the valid indexes are 0, 1, and 2.

JavaScript provides for...of for iterating through the values of iterable objects.const colors = ["red", "green", "blue"];

for (const color of colors) {
    console.log(color);
}

This loop visits each element in the array directly. No index variable is required unless you specifically need one.

for...of is often clearer than an indexed for loop when the index itself is not important. It also works with strings, sets, maps, and other iterable objects.

Example with a string:for (const ch of "cat") {
    console.log(ch);
}

Output:c
a
t

An iterable object is any object that can produce values in sequence for constructs like for...of.

The for...in loop is different. It iterates over property names.const student = {
    name: "Ava",
    major: "CS",
    level: "Sophomore"
};

for (const key in student) {
    console.log(key, "=>", student[key]);
}

Output:name => Ava
major => CS
level => Sophomore

Using for...in on arrays when you really want the elements.const nums = [10, 20, 30];

for (const x in nums) {
    console.log(x);
}

Output:0
1
2

That loop prints indexes as strings, not the array values. If you want 10, 20, and 30, use for...of.

forEach() executes a function once for each element.const nums = [2, 4, 6];

nums.forEach(function (value, index) {
    console.log("Index:", index, "Value:", value);
});

An arrow-function version is common:nums.forEach((value, index) => {
    console.log("Index:", index, "Value:", value);
});

map() transforms each element and returns a new array.const nums = [1, 2, 3];
const squares = nums.map(n => n * n);

console.log(squares); // [1, 4, 9]

filter() keeps only the elements that pass a test.const nums = [1, 2, 3, 4, 5, 6];
const evens = nums.filter(n => n % 2 === 0);

console.log(evens); // [2, 4, 6]

reduce() combines all elements into one final result.const nums = [1, 2, 3, 4];
const total = nums.reduce((sum, n) => sum + n, 0);

console.log(total); // 10

This program combines the chapter’s major iteration techniques in a single example. It uses the same small set of data in several different ways so that the reader can compare loop syntax, behavior, and purpose. The goal is not to suggest that every real program should use all iteration styles at once. That would be absurd and mildly theatrical. The goal is to show that different iteration tools solve different kinds of problems.

The demonstration includes a while loop for condition-controlled repetition, a do...while loop for repetition that must occur at least once, a classic for loop for indexed traversal, a for...of loop for iterable values, a for...in loop for object properties, and the array methods forEach(), map(), filter(), and reduce(). It also demonstrates break and continue, two control statements that alter loop flow.<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>JavaScript Iteration Demo</title>

    <style>
        .div1{
            width:75%;
            background-color: cornsilk;
            margin-left: auto;
            margin-right: auto;
            margin-top: 50px;
            margin-bottom: 50px;
            padding: 20px;
            font-family: Arial, Helvetica, sans-serif;
        }

        button{
            padding: 10px 14px;
            margin-top: 10px;
            margin-bottom: 20px;
            cursor: pointer;
        }

        pre{
            background-color: #fffdf5;
            border: 1px solid #ccc;
            padding: 15px;
            white-space: pre-wrap;
        }
    </style>
</head>
<body>

    <div class="div1">
        <h1>JavaScript Iteration Demo</h1>
        <p>
            This program demonstrates major JavaScript iteration techniques in one place:
            while, do...while, for, for...of, for...in, forEach(), map(), filter(), and reduce().
        </p>

        <button onclick="runDemo()">Run Demo</button>

        <pre id="output"></pre>
    </div>

    <script>
        function runDemo() {
            const output = document.getElementById("output");
            output.textContent = "";

            function print(message = "") {
                output.textContent += message + "\n";
            }

            // ------------------------------------------------------------
            // Sample data used throughout the demonstration
            // ------------------------------------------------------------
            const scores = [82, 91, 76, 88, 95, 67, 100];
            const student = {
                name: "Ava",
                major: "Computer Science",
                level: "Sophomore"
            };
            const word = "loop";

            print("JAVASCRIPT ITERATION DEMONSTRATION");
            print("==================================");
            print();
            print("Data Samples")
            print("score data: 82, 91, 76, 88, 95, 67, 100");
            print("student data => name: Ava, major: Computer Science, level: Sophomore");
            print("word data : loop");
            print();

            // ------------------------------------------------------------
            // 1. while loop
            // Repeats while a condition remains true
            // ------------------------------------------------------------
            print("1. while loop");
            let count = 1;
            while (count <= 3) {
                print("while count = " + count);
                count++;
            }
            print();

            // ------------------------------------------------------------
            // 2. do...while loop
            // Executes at least once because the test happens afterward
            // ------------------------------------------------------------
            print("2. do...while loop");
            let menuChoice = 1;
            do {
                print("do...while choice = " + menuChoice);
                menuChoice++;
            } while (menuChoice <= 3);
            print();

            // ------------------------------------------------------------
            // 3. classic for loop
            // Best when you need an index or counter
            // ------------------------------------------------------------
            print("3. classic for loop");
            for (let i = 0; i < scores.length; i++) {
                print("scores[" + i + "] = " + scores[i]);
            }
            print();

            // ------------------------------------------------------------
            // 4. for...of loop
            // Iterates directly over values in an iterable
            // ------------------------------------------------------------
            print("4. for...of loop over array values");
            for (const score of scores) {
                print("score = " + score);
            }
            print();

            // ------------------------------------------------------------
            // 5. for...of loop over a string
            // Strings are iterable in JavaScript
            // ------------------------------------------------------------
            print("5. for...of loop over string characters");
            for (const ch of word) {
                print("character = " + ch);
            }
            print();

            // ------------------------------------------------------------
            // 6. for...in loop
            // Iterates over property names of an object
            // ------------------------------------------------------------
            print("6. for...in loop over object properties");
            for (const key in student) {
                print(key + " => " + student[key]);
            }
            print();

            // ------------------------------------------------------------
            // 7. forEach()
            // Good for side effects such as printing
            // ------------------------------------------------------------
            print("7. forEach()");
            scores.forEach(function(value, index) {
                print("Index " + index + " has value " + value);
            });
            print();

            // ------------------------------------------------------------
            // 8. map()
            // Creates a new array by transforming each element
            // ------------------------------------------------------------
            print("8. map()");
            const curvedScores = scores.map(score => score + 5);
            print("Original scores: " + scores.join(", "));
            print("Curved scores:   " + curvedScores.join(", "));
            print();

            // ------------------------------------------------------------
            // 9. filter()
            // Creates a new array containing only matching elements
            // ------------------------------------------------------------
            print("9. filter()");
            const passingScores = scores.filter(score => score >= 70);
            print("Passing scores: " + passingScores.join(", "));
            print();

            // ------------------------------------------------------------
            // 10. reduce()
            // Combines all elements into one final value
            // ------------------------------------------------------------
            print("10. reduce()");
            const total = scores.reduce((sum, score) => sum + score, 0);
            const average = total / scores.length;
            print("Total score = " + total);
            print("Average score = " + average.toFixed(2));
            print();

            // ------------------------------------------------------------
            // 11. break and continue inside a loop
            // break exits the loop early
            // continue skips the current iteration
            // ------------------------------------------------------------
            print("11. break and continue");
            for (const score of scores) {
                if (score < 70) {
                    print("Skipping failing score: " + score);
                    continue;
                }

                if (score === 100) {
                    print("Perfect score found. Stopping loop.");
                    break;
                }

                print("Accepted score: " + score);
            }
            print();

            // ------------------------------------------------------------
            // 12. A full practical example
            // Process scores to produce a mini report
            // ------------------------------------------------------------
            print("12. Practical score report");

