                }

                if (score < lowest) {
                    lowest = score;
                }
            }

            print("Highest score = " + highest);
            print("Lowest score = " + lowest);

            const honorRoll = scores.filter(score => score >= 90);
            print("Honor roll scores = " + honorRoll.join(", "));

            const letterGrades = scores.map(function(score) {
                if (score >= 90) return "A";
                if (score >= 80) return "B";
                if (score >= 70) return "C";
                if (score >= 60) return "D";
                return "F";
            });

            print("Letter grades = " + letterGrades.join(", "));
            print();

            // ------------------------------------------------------------
            // 13. Final message
            // ------------------------------------------------------------
            print("Demo complete.");
        }
